#include<bits/stdc++.h>
using namespace std;
int a[10]={0,-2,-2,-1,-1,1,1,2,2};
int b[10]={0,1,-1,2,-2,2,-2,1,-1};
int main() {
	int mx,my,jx,jy,zx,zy,x,res=0,y;
	cin>>jx>>jy>>zx>>zy>>mx>>my;
	for(int i=1;i<9;i++)
	{
		x=mx+a[i];
		y=my+b[i];
		if(x>=1&&y>=1&&x<=9&&y<=9)
		{
			if(x!=jx&&y!=jy&&x!=zx&&y!=zy)
			{
				if(abs(x-jx)+abs(y-jy)==3)
				{
					if(abs(x-zx)+abs(y-zy)==3)
					{
						res=1;
						break;
					}
				}
				
				
			}
		}
	}
	if(res){
		cout<<"Yes";
	}else{
		cout<<"No";
	}

    return 0;

}
